content.problemStatement:
Little Elephant loves bubble sorting.

Bubble sorting for any array **A** of **n** integers works in the   following way:   

 var int i, j; 
 for i from n downto 1 
 { 
 for j from 1 to i-1  
 {  
 if (A[j] &gt; A[j+1]) 
 swap(A[j], A[j+1]) 
 } 
} 

You are given an array **B** of **n** integers. Then the array **A** is created using array **B** as following : for each **i** (**1 &lt;= i &lt;= n**), we set **Ai** = **Bi + d** with the   probability **Pi**, otherwise **Ai** =   **Bi**.

Help Little Elephant to find the expect number of swaps that bubble sorting   will make when the array **A** is sorted with the above bubble sorting   algorithm.

code.C:
#include <stdio.h>
#include <stdlib.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n, d;
        scanf("%d %d", &n, &d);
        int* B = (int*)malloc(n * sizeof(int));
        int* P = (int*)malloc(n * sizeof(int));
        for (int i = 0; i < n; i++) {
            scanf("%d", &B[i]);
        }
        for (int i = 0; i < n; i++) {
            scanf("%d", &P[i]);
        }
        double expectedSwaps = 0;
        for (int i = 0; i < n - 1; i++) {
            for (int j = i + 1; j < n; j++) {
                double probability = (P[i] / 100.0) * (1 - P[j] / 100.0);
                if (B[i] + d > B[j]) {
                    expectedSwaps += probability;
                }
                probability = (1 - P[i] / 100.0) * (P[j] / 100.0);
                if (B[i] < B[j] + d) {
                    expectedSwaps += probability;
                }
            }
        }
        printf("%.4f\n", expectedSwaps);
        free(B);
        free(P);
    }
    return 0;
}

